/**
 * Workspace symbol search across all modules in a document.
 */

import { check } from '@agile-sofl/parser'
import type { TextDocument } from 'vscode-languageserver-textdocument'
import { SymbolInformation, SymbolKind } from 'vscode-languageserver/node.js'
import { spanToRange } from './position.js'

const KIND_MAP = {
  const: SymbolKind.Constant,
  type: SymbolKind.Class,
  var: SymbolKind.Variable,
  process: SymbolKind.Method,
  function: SymbolKind.Function
} as const

export function collectWorkspaceSymbols(document: TextDocument, query?: string): SymbolInformation[] {
  const { ast } = check(document.getText())
  if (!ast || ast.type !== 'program') return []

  const needle = query?.trim().toLowerCase() ?? ''
  const symbols: SymbolInformation[] = []

  for (const mod of ast.modules) {
    const modLabel = mod.isSystem ? `SYSTEM_${mod.name}` : mod.name
    if (!needle || modLabel.toLowerCase().includes(needle)) {
      symbols.push({
        name: modLabel,
        kind: SymbolKind.Module,
        location: { uri: document.uri, range: spanToRange(document, mod.span) },
        containerName: undefined
      })
    }

    for (const sym of [
      ...mod.consts.map((c) => ({ kind: 'const' as const, name: c.name, span: c.span })),
      ...mod.types.map((t) => ({ kind: 'type' as const, name: t.name, span: t.span })),
      ...mod.vars.map((v) => ({ kind: 'var' as const, name: v.variable.name, span: v.variable.span })),
      ...mod.processes.map((p) => ({ kind: 'process' as const, name: p.name, span: p.span })),
      ...mod.functions.map((f) => ({ kind: 'function' as const, name: f.name, span: f.span }))
    ]) {
      if (needle && !sym.name.toLowerCase().includes(needle)) continue
      symbols.push({
        name: sym.name,
        kind: KIND_MAP[sym.kind],
        location: { uri: document.uri, range: spanToRange(document, sym.span) },
        containerName: modLabel
      })
    }
  }

  return symbols
}
